/* patched thumbnail-loader.compat.min.js (API schema-aware) */
(function(){
  var PAGEKEY_ATTR="data-psom-key";
  function q(sel){return document.querySelector(sel)}
  function getPageKey(){
    var el=document.querySelector("["+PAGEKEY_ATTR+"]");
    return el?el.getAttribute(PAGEKEY_ATTR):null;
  }
  function lang(){try{return (window.IGDC_CORE&&IGDC_CORE.lang())||document.documentElement.lang||'ko'}catch(e){return 'ko'}}
  function mapItemShape(x){
    if(!x) return null;
    return {
      title: x.title||x.name||x.label||"",
      href: x.href||x.url||"#",
      img: x.img||x.image||x.thumbnail||"",
      desc: x.desc||x.description||""
    };
  }
  function pickFirstArray(json){
    if(!json||typeof json!=='object')return null;
    for(var k in json){
      if(!Object.prototype.hasOwnProperty.call(json,k))continue;
      var v=json[k];
      if(Array.isArray(v) && v.length) return v;
      if(v&&typeof v==='object'){
        var arr=pickFirstArray(v);
        if(arr) return arr;
      }
    }
    return null;
  }
  function parseApiJson(json,page){
    var arr=null;
    try{
      if(page==="socialnetwork" && json && json.grid && Array.isArray(json.grid.sections)){
        arr=[];
        json.grid.sections.forEach(function(sec){
          if(sec && Array.isArray(sec.items)) arr=arr.concat(sec.items);
        });
        if(arr.length) return arr;
      }
      if((page==="tour"||page==="networkhub") && json && json.rightPanel && Array.isArray(json.rightPanel.items)){
        return json.rightPanel.items;
      }
      if((page==="home"||page==="distributionhub") && json && json.data){
        if(Array.isArray(json.data)) return json.data;
        if(json.data.items && Array.isArray(json.data.items)) return json.data.items;
        var any = pickFirstArray(json.data);
        if(any) return any;
      }
      // generic fallback: first array anywhere
      var anyTop = pickFirstArray(json);
      if(anyTop) return anyTop;
    }catch(e){}
    return null;
  }
  function render(items){
    var host=document.querySelector("["+PAGEKEY_ATTR+"]");
    if(!host) return;
    var html=(items||[]).map(function(it){
      var s=mapItemShape(it)||{};
      return '<a class="thumb-card" href="'+(s.href||'#')+'"><img loading="lazy" src="'+(s.img||'')+'"/><div class="t">'+(s.title||'')+'</div></a>';
    }).join("");
    host.innerHTML=html||'<div class="thumb-empty">No items</div>';
  }
  function tryApiFirst(page){
    var u="/api/feed?page="+encodeURIComponent(page)+"&lang="+encodeURIComponent(lang());
    if(window.IGDC_CORE && IGDC_CORE.country){u+="&country="+encodeURIComponent(IGDC_CORE.country());}
    return fetch(u,{credentials:"omit"})
      .then(function(r){ if(!r.ok) throw new Error("HTTP "+r.status); return r.json(); })
      .then(function(json){
        var arr=parseApiJson(json,page);
        if(arr&&arr.length){ render(arr); return true; }
        throw new Error("schema-miss");
      });
  }
  function tryPsomFallback(page){
    return fetch("/psom.json",{credentials:"omit"}).then(function(r){return r.json();}).then(function(psom){
      var L=lang();
      var bucket=(psom && psom[page] && (psom[page][L]||psom[page]["_default"]))||null;
      var items=null;
      if(bucket && Array.isArray(bucket.items)) items=bucket.items;
      if(!items && bucket){ // search any array in bucket
        items=(function find(b){for(var k in b){var v=b[k];if(Array.isArray(v))return v;if(v&&typeof v==='object'){var got=find(v);if(got)return got;}}return null;})(bucket);
      }
      if(items&&items.length){ render(items); return true; }
      throw new Error("psom-empty");
    });
  }
  function boot(){
    var page=getPageKey(); if(!page) return;
    tryApiFirst(page).catch(function(){ return tryPsomFallback(page); }).catch(function(){
      render([]);
    });
  }
  if(document.readyState==="loading") document.addEventListener("DOMContentLoaded",boot);
  else boot();
  window.__THUMB_VERSION__="compat-geo-parse-20251006";
})();